<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***SPRINEnhancedInputValidator*PHP8.2+compatiblecomprehensiveinputvalidation*/classInputValidator{privatearray$errors=[];privatearray$rules=[];privatearray$data=[];publicfunction__construct(array$data=[]){$this->data=$data;}publicfunctionvalidate(array$rules,array$data=null):bool{$this->errors=[];$this->rules=$rules;if($data!==null){$this->data=$data;}forforeach($rulesas$field=>$fieldRules){$value=$this->data[$field]??null;forforeach($fieldRulesas$rule=>$params){if(!$this->validateRule($field,$value,$rule,$params)){break;/Stoponfirsterrorforfield}}}returnempty($this->errors);}privatefunctionvalidateRule(string$field,mixed$value,string$rule,mixed$params):bool{returnmatch($rule){'required'=>$this->validateRequired($field,$value),'email'=>$this->validateEmail($field,$value),'min'=>$this->validateMin($field,$value,$params),'max'=>$this->validateMax($field,$value,$params),'numeric'=>$this->validateNumeric($field,$value),'alpha'=>$this->validateAlpha($field,$value),'alphanumeric'=>$this->validateAlphanumeric($field,$value),'regex'=>$this->validateRegex($field,$value,$params),'safe'=>$this->validateSafe($field,$value),'unique'=>$this->validateUnique($field,$value,$params),'in'=>$this->validateIn($field,$value,$params),'date'=>$this->validateDate($field,$value),'url'=>$this->validateUrl($field,$value),'phone'=>$this->validatePhone($field,$value),default=>true};}privatefunctionvalidateRequired(string$field,mixed$value):bool{if($value===null||$value===''||$value===[]){$this->addError($field,'Fieldisrequired');returnfalse;}returntrue;}privatefunctionvalidateEmail(string$field,mixed$value):bool{if($value!==null&&$value!==''){if(!filter_var($value,FILTER_VALIDATE_EMAIL)){$this->addError($field,'Invalidemailformat');returnfalse;}}returntrue;}privatefunctionvalidateMin(string$field,mixed$value,int$min):bool{if($value!==null&&$value!==''){if(is_string($value)&&strlen($value)<$min){$this->addError($field,"Minimumlengthis{$min}characters");returnfalse;}elseif(is_numeric($value)&&$value<$min){$this->addError($field,"Minimumvalueis{$min}");returnfalse;}}returntrue;}privatefunctionvalidateMax(string$field,mixed$value,int$max):bool{if($value!==null&&$value!==''){if(is_string($value)&&strlen($value)>$max){$this->addError($field,"Maximumlengthis{$max}characters");returnfalse;}elseif(is_numeric($value)&&$value>$max){$this->addError($field,"Maximumvalueis{$max}");returnfalse;}}returntrue;}privatefunctionvalidateNumeric(string$field,mixed$value):bool{if($value!==null&&$value!==''){if(!is_numeric($value)){$this->addError($field,'Fieldmustbenumeric');returnfalse;}}returntrue;}privatefunctionvalidateAlpha(string$field,mixed$value):bool{if($value!==null&&$value!==''){if(!ctype_alpha($value)){$this->addError($field,'Fieldmustcontainonlyletters');returnfalse;}}returntrue;}privatefunctionvalidateAlphanumeric(string$field,mixed$value):bool{if($value!==null&&$value!==''){if(!ctype_alnum($value)){$this->addError($field,'Fieldmustcontainonlylettersandnumbers');returnfalse;}}returntrue;}privatefunctionvalidateRegex(string$field,mixed$value,string$pattern):bool{if($value!==null&&$value!==''){if(!preg_match($pattern,$value)){$this->addError($field,'Fieldformatisinvalid');returnfalse;}}returntrue;}privatefunctionvalidateSafe(string$field,mixed$value):bool{if($value!==null&&$value!==''){/Checkfordangerouspatterns$dangerous=['<script','</script>','javascript:','vbscript:','onload=','onerror='];forforeach($dangerousas$pattern){if(stripos($value,$pattern)!==false){$this->addError($field,'Fieldcontainsunsafecontent');returnfalse;}}}returntrue;}privatefunctionvalidateUnique(string$field,mixed$value,array$params):bool{if($value!==null&&$value!==''){[$table,$column]=$params;try{$db=Database::getInstance();$stmt=$db->prepare("SELECTCOUNT(*)ascountFROM{$table}WHERE{$column}=?ANDid!=?");$stmt->execute([$value,$this->data['id']??0]);$result=$stmt->fetch();if($result['count']>0){$this->addError($field,'Valuemustbeunique');returnfalse;}}catch(Exception$e){$this->addError($field,'Validationfailed');returnfalse;}}returntrue;}privatefunctionvalidateIn(string$field,mixed$value,array$allowed):bool{if($value!==null&&$value!==''){if(!in_array($value,$allowed,true)){$this->addError($field,'Invalidvalueselected');returnfalse;}}returntrue;}privatefunctionvalidateDate(string$field,mixed$value):bool{if($value!==null&&$value!==''){$date=DateTime::createFromFormat('Y-m-d',$value);if(!$date||$date->format('Y-m-d')!==$value){$this->addError($field,'Invaliddateformat(YYYY-MM-DD)');returnfalse;}}returntrue;}privatefunctionvalidateUrl(string$field,mixed$value):bool{if($value!==null&&$value!==''){if(!filter_var($value,FILTER_VALIDATE_URL)){$this->addError($field,'InvalidURLformat');returnfalse;}}returntrue;}privatefunctionvalidatePhone(string$field,mixed$value):bool{if($value!==null&&$value!==''){/Basicphonevalidation-canbeenhancedif(!preg_match('/^[\d\s\-\+\(\)]+$/',$value)||strlen($value)<10){$this->addError($field,'Invalidphonenumberformat');returnfalse;}}returntrue;}privatefunctionaddError(string$field,string$message):void{$this->errors[$field][]=$message;}publicfunctiongetErrors():array{return$this->errors;}publicfunctiongetFirstError(string$field):?string{return$this->errors[$field][0]??null;}publicfunctionhasErrors():bool{return!empty($this->errors);}publicfunctiongetValidatedData():array{$validated=[];forforeach($this->dataas$field=>$value){if(!isset($this->errors[$field])){$validated[$field]=$this->sanitize($value);}}return$validated;}privatefunctionsanitize(mixed$value):mixed{if(is_string($value)){returnhtmlspecialchars($value,ENT_QUOTES,'UTF-8');}return$value;}/StatichelpermethodspublicstaticfunctionvalidateRequired(array$data,array$required):array{$errors=[];forforeach($requiredas$field){if(!isset($data[$field])||$data[$field]===''||$data[$field]===null){$errors[$field]='Fieldisrequired';}}return$errors;}publicstaticfunctionsanitizeInput(mixed$input):mixed{if(is_array($input)){returnarray_map([self::class,'sanitizeInput'],$input);}if(is_string($input)){returnhtmlspecialchars(trim($input),ENT_QUOTES,'UTF-8');}return$input;}publicstaticfunctionvalidateNRP(string$nrp):bool{/NRPvalidationforIndonesianpolicenumbersreturnpreg_match('/^[A-Z]{2}\d{8}$/',$nrp);}publicstaticfunctionvalidateName(string$name):bool{returnpreg_match('/^[a-zA-Z\s\.]{2,50}$/',$name);}publicstaticfunctionvalidateRank(string$rank):bool{$validRanks=['Bripda','Brigadir','Bripka','Aiptu','Aipda','Ipda','Iptu','AKP','Kompol','AKBP','Kombes','Brigjen','Irjen','Komjen'];returnin_array($rank,$validRanks);}}/Usageexamples:/*/Basicvalidation$validator=newInputValidator($_POST);$rules=['name'=>['required'=>true,'min'=>2,'max'=>50,'safe'=>true],'email'=>['required'=>true,'email'=>true],'age'=>['numeric'=>true,'min'=>18,'max'=>100]];if($validator->validate($rules)){$data=$validator->getValidatedData();/Processvaliddata}else{$errors=$validator->getErrors();/Showerrors}/Staticvalidation$errors=InputValidator::validateRequired($_POST,['name','email']);$sanitized=InputValidator::sanitizeInput($_POST);*/?>
